          initial={{ pathLength: 0, opacity: 0 }}
          animate={{ pathLength: 1, opacity: 0.7 }}
          transition={{ duration: 1.5, delay: arc.d, repeat: Infinity, repeatType: "reverse", repeatDelay: 1 }} />
      ))}
    </svg>
  );
}

